properties.css:
/* Eligibility column pills */
td.column_disposition {
  white-space: nowrap;
  text-align: center;
}
td.column_disposition .regbb-pill {
  display: inline-block;
  padding: 0.18em 0.7em;
  border-radius: 999px;
  font-size: 0.85em;
  font-weight: 600;
  line-height: 1.4;
  text-transform: uppercase;
  letter-spacing: 0.04em;
}
td.column_disposition .regbb-pill-passed         { background: #d1fae5; color: #065f46; border: 1px solid #6ee7b7; }
td.column_disposition .regbb-pill-pending_review { background: #fef3c7; color: #92400e; border: 1px solid #fcd34d; }
td.column_disposition .regbb-pill-failed         { background: #fee2e2; color: #991b1b; border: 1px solid #fca5a5; }
td.column_disposition .regbb-pill-indeterminate  { background: #e0e7ff; color: #3730a3; border: 1px solid #a5b4fc; }
td.column_disposition .regbb-pill-na             { background: #f3f4f6; color: #6b7280; border: 1px dashed #d1d5db; font-style: italic; }

/* Application status column pills (Phase 2-a state machine) */
td.column_status {
  white-space: nowrap;
  text-align: center;
}
td.column_status .regbb-pill {
  display: inline-block;
  padding: 0.18em 0.7em;
  border-radius: 999px;
  font-size: 0.85em;
  font-weight: 600;
  line-height: 1.4;
  text-transform: uppercase;
  letter-spacing: 0.04em;
}
td.column_status .regbb-pill-approved      { background: #bbf7d0; color: #166534; border: 1px solid #4ade80; }
td.column_status .regbb-pill-auto_approved { background: #d1fae5; color: #065f46; border: 1px solid #6ee7b7; }
td.column_status .regbb-pill-rejected      { background: #fecaca; color: #7f1d1d; border: 1px solid #f87171; }
td.column_status .regbb-pill-auto_rejected { background: #fee2e2; color: #991b1b; border: 1px solid #fca5a5; }
td.column_status .regbb-pill-pending       { background: #fef3c7; color: #92400e; border: 1px solid #fcd34d; }
td.column_status .regbb-pill-sent_back     { background: #dbeafe; color: #1e40af; border: 1px solid #60a5fa; }
td.column_status .regbb-pill-na            { background: #f3f4f6; color: #6b7280; border: 1px dashed #d1d5db; font-style: italic; }
